use std::io::{BufReader, stdin};

fn main() {
    let mut reader = stdin();
    let mut s = String::new();
    reader.read_line(&mut s).unwrap();
    let N = s.trim_right().parse::<i32>().unwrap();
    s.clear();
    reader.read_line(&mut s).unwrap();
    let A = s.trim_right().parse::<i32>().unwrap();
    s.clear();
    reader.read_line(&mut s).unwrap();
    let B = s.trim_right().parse::<i32>().unwrap();
    s.clear();
    reader.read_line(&mut s).unwrap();
    let C = s.trim_right().parse::<i32>().unwrap();

    let mut ans = 0;
    let mut loc = 0;
    for x in 1..N {
        if loc == 0 {   // rabbit
            if A > B {
                ans = ans + B;
                loc = 2;
            } else {
                ans = ans + A;
                loc = 1;
            }
        } else if loc == 1 {    // owl
            if A > C {
                ans = ans + C;
                loc = 2;
            } else {
                ans = ans + A;
                loc = 0;
            }
        } else {    // eeyore
            if B > C  {
                ans = ans + C;
                loc = 1;
            } else {
                ans = ans + B;
                loc = 0;
            }
        }
    }

    println!("{}", ans);
}
